1	// Domain types
2	
3	export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone' | string;
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface Customer {
13	  yearsWithMHPCO: number;
14	}
15	
16	export interface QuoteStep {
17	  op: 'quote';
18	  items: Item[];
19	}
20	
21	export interface DamageEntry {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface Incident {
27	  cause: string;
28	  damages: DamageEntry[];
29	}
30	
31	export interface ClaimStep {
32	  op: 'claim';
33	  policy: number;
34	  incident: Incident;
35	}
36	
37	export type Step = QuoteStep | ClaimStep;
38	
39	export interface Scenario {
40	  customer: Customer;
41	  steps: Step[];
42	}
43	
44	export interface QuoteResult {
45	  premium: number;
46	}
47	
48	export interface ClaimResult {
49	  payout: number;
50	  remainingCap: number;
51	}
52	
53	export type StepResult = QuoteResult | ClaimResult;
54	
55	export interface ScenarioOutput {
56	  results: StepResult[];
57	}
58	
59	// Price list
60	
61	const MAIN_ITEMS: Record<string, { value: number; basePremium: number }> = {
62	  sword:  { value: 1000, basePremium: 100 },
63	  amulet: { value: 600,  basePremium: 60 },
64	  staff:  { value: 800,  basePremium: 80 },
65	  potion: { value: 400,  basePremium: 40 },
66	};
67	
68	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
69	const COMPONENT_VALUE = 250;
70	const COMPONENT_PREMIUM = 25;
71	const COMPONENT_BLOCK_PREMIUM = 60;
72	const COMPONENT_BLOCK_SIZE = 3;
73	
74	const PROCESSING_FEE = 5;
75	const DEDUCTIBLE = 100;
76	
77	function isKnownItemType(type: string): boolean {
78	  return type in MAIN_ITEMS || COMPONENT_TYPES.has(type);
79	}
80	
81	function isComponent(type: string): boolean {
82	  return COMPONENT_TYPES.has(type);
83	}
84	
85	function itemInsuranceValue(type: string): number {
86	  if (type in MAIN_ITEMS) return MAIN_ITEMS[type].value;
87	  if (isComponent(type)) return COMPONENT_VALUE;
88	  throw new Error(`Unknown item type: ${type}`);
89	}
90	
91	function itemBasePremium(type: string): number {
92	  if (type in MAIN_ITEMS) return MAIN_ITEMS[type].basePremium;
93	  if (isComponent(type)) return COMPONENT_PREMIUM;
94	  throw new Error(`Unknown item type: ${type}`);
95	}
96	
97	// Premium calculation
98	
99	interface PolicyRecord {
100	  insuranceSum: number;
101	  cap: number;
102	  remainingCap: number;
103	  items: Item[];
104	}
105	
106	function validateItems(items: Item[]): void {
107	  for (const it of items) {
108	    if (!isKnownItemType(it.type)) {
109	      throw new Error(`Unknown item type: ${it.type}`);
110	    }
111	  }
112	}
113	
114	function policyInsuranceSum(items: Item[]): number {
115	  return items.reduce((sum, it) => sum + itemInsuranceValue(it.type), 0);
116	}
117	
118	function itemSurcharge(item: Item): number {
119	  const base = itemBasePremium(item.type);
120	  let surcharge = 0;
121	  if (item.cursed) surcharge += base * 0.5;
122	  if ((item.enchantment ?? 0) >= 5) surcharge += base * 0.3;
123	  return surcharge;
124	}
125	
126	function componentBlockAdjustment(items: Item[]): number {
127	  // For each component type, replace each full block of 3 with the discounted price
128	  const counts = new Map<string, number>();
129	  for (const it of items) {
130	    if (isComponent(it.type)) {
131	      counts.set(it.type, (counts.get(it.type) ?? 0) + 1);
132	    }
133	  }
134	  let adjustment = 0;
135	  for (const [, count] of counts) {
136	    if (count === COMPONENT_BLOCK_SIZE) {
137	      const blockSavings = COMPONENT_BLOCK_SIZE * COMPONENT_PREMIUM - COMPONENT_BLOCK_PREMIUM;
138	      adjustment -= blockSavings;
139	    }
140	  }
141	  return adjustment;
142	}
143	
144	function roundUp(value: number): number {
145	  // Round in MHPCO's favor for premium: ceiling
146	  return Math.ceil(value - 1e-9); // tolerate floating-point noise
147	}
148	
149	function roundDown(value: number): number {
150	  // Round in MHPCO's favor for payout: floor
151	  return Math.floor(value + 1e-9);
152	}
153	
154	export function computePremium(items: Item[], customer: Customer, isFirstContract: boolean): number {
155	  validateItems(items);
156	
157	  if (items.length === 0) {
158	    return PROCESSING_FEE;
159	  }
160	
161	  // Sum item base premiums
162	  const itemBaseSum = items.reduce((sum, it) => sum + itemBasePremium(it.type), 0);
163	
164	  // Component block discount
165	  const blockAdjustment = componentBlockAdjustment(items);
166	
167	  const policyBase = itemBaseSum + blockAdjustment;
168	
169	  // Per-item surcharges (cursed, high enchantment) — applied to item base premiums
170	  const itemSurchargeTotal = items.reduce((sum, it) => sum + itemSurcharge(it), 0);
171	
172	  // Policy-wide modifiers applied to policyBase
173	  let policyMods = 0;
174	  if (customer.yearsWithMHPCO >= 2) policyMods -= policyBase * 0.2;
175	  // First-insurance surcharge: each item in a quote is treated as a first insurance
176	  policyMods += policyBase * 0.1;
177	  if (!isFirstContract) policyMods -= policyBase * 0.15;
178	
179	  const subtotal = policyBase + itemSurchargeTotal + policyMods;
180	  const total = subtotal + PROCESSING_FEE;
181	  return roundUp(total);
182	}
183	
184	// Claim calculation
185	
186	function itemReimbursementFraction(item: Item): number {
187	  // dragon material → full, but if also enchantment >=8, 50% wins
188	  const highEnchant = (item.enchantment ?? 0) >= 8;
189	  if (highEnchant) return 0.5;
190	  return 1.0;
191	}
192	
193	function findAndConsumeItem(pool: Item[], itemType: string): Item | undefined {
194	  // Choose the item that yields the worst (highest) reimbursement for the customer?
195	  // Spec is ambiguous. Use the first matching item to keep behavior deterministic.
196	  const idx = pool.findIndex(it => it.type === itemType);
197	  if (idx === -1) return undefined;
198	  return pool.splice(idx, 1)[0];
199	}
200	
201	export function computeClaim(policy: PolicyRecord, incident: Incident): { payout: number; remainingCap: number } {
202	  // Validate damages: every damaged item type must be present in policy in sufficient count
203	  const pool: Item[] = policy.items.map(it => ({ ...it }));
204	  const resolved: { item: Item; amount: number }[] = [];
205	
206	  for (const dmg of incident.damages) {
207	    if (dmg.amount < 0) {
208	      throw new Error(`Negative damage amount: ${dmg.amount}`);
209	    }
210	    if (!isKnownItemType(dmg.itemType)) {
211	      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
212	    }
213	    const item = findAndConsumeItem(pool, dmg.itemType);
214	    if (!item) {
215	      throw new Error(`Damaged item ${dmg.itemType} is not part of the policy`);
216	    }
217	    resolved.push({ item, amount: dmg.amount });
218	  }
219	
220	  let totalPayout = 0;
221	  let remaining = policy.remainingCap;
222	  for (const { item, amount } of resolved) {
223	    const isDragon = item.material === 'dragon';
224	    const highEnchant = (item.enchantment ?? 0) >= 8;
225	    let reimbursable: number;
226	    if (highEnchant) {
227	      reimbursable = amount * 0.5;
228	    } else if (isDragon) {
229	      reimbursable = amount;
230	    } else {
231	      reimbursable = amount;
232	    }
233	    let perItem = reimbursable - DEDUCTIBLE;
234	    if (perItem < 0) perItem = 0;
235	    // Apply cap progressively
236	    const rounded = roundDown(perItem);
237	    const granted = Math.min(rounded, remaining);
238	    totalPayout += granted;
239	    remaining -= granted;
240	  }
241	
242	  return { payout: totalPayout, remainingCap: remaining };
243	}
244	
245	// Scenario runner
246	
247	export function runScenario(scenario: Scenario): ScenarioOutput {
248	  const results: StepResult[] = [];
249	  const policies: Map<number, PolicyRecord> = new Map();
250	  let quoteCount = 0;
251	
252	  for (let i = 0; i < scenario.steps.length; i++) {
253	    const step = scenario.steps[i];
254	    if (step.op === 'quote') {
255	      const isFirstContract = quoteCount === 0;
256	      const premium = computePremium(step.items, scenario.customer, isFirstContract);
257	      const insuranceSum = policyInsuranceSum(step.items);
258	      const policy: PolicyRecord = {
259	        insuranceSum,
260	        cap: insuranceSum * 2,
261	        remainingCap: insuranceSum * 2,
262	        items: step.items.map(it => ({ ...it })),
263	      };
264	      policies.set(i, policy);
265	      quoteCount++;
266	      results.push({ premium });
267	    } else if (step.op === 'claim') {
268	      const policy = policies.get(step.policy);
269	      if (!policy) {
270	        throw new Error(`Claim references unknown policy step: ${step.policy}`);
271	      }
272	      const { payout, remainingCap } = computeClaim(policy, step.incident);
273	      policy.remainingCap = remainingCap;
274	      results.push({ payout, remainingCap });
275	    } else {
276	      throw new Error(`Unknown op: ${(step as { op: string }).op}`);
277	    }
278	  }
279	
280	  return { results };
281	}
