1	#!/usr/bin/env node
2	import { runScenario, Scenario } from './claim-office.js';
3	
4	async function readStdin(): Promise<string> {
5	  return new Promise((resolve, reject) => {
6	    let data = '';
7	    process.stdin.setEncoding('utf8');
8	    process.stdin.on('data', chunk => { data += chunk; });
9	    process.stdin.on('end', () => resolve(data));
10	    process.stdin.on('error', err => reject(err));
11	  });
12	}
13	
14	async function main(): Promise<void> {
15	  try {
16	    const input = await readStdin();
17	    const scenario = JSON.parse(input) as Scenario;
18	    const output = runScenario(scenario);
19	    process.stdout.write(JSON.stringify(output) + '\n');
20	  } catch (err) {
21	    const msg = err instanceof Error ? err.message : String(err);
22	    process.stderr.write(`Error: ${msg}\n`);
23	    process.exit(1);
24	  }
25	}
26	
27	main();
