4	function quote(items: Array<Record<string, unknown>>, yearsWithMHPCO = 0, priorQuotes: Array<Record<string, unknown>>[] = []): number {
5	  const steps: Array<Record<string, unknown>> = [];
6	  for (const prior of priorQuotes) {
7	    steps.push({ op: 'quote', items: prior });
8	  }
9	  steps.push({ op: 'quote', items });
10	  const result = runScenario({
11	    customer: { yearsWithMHPCO },
12	    steps: steps as Scenario['steps'],
13	  });
14	  const last = result.results[result.results.length - 1] as { premium: number };
15	  return last.premium;
16	}
