// Claim calculation

function itemReimbursementFraction(item: Item): number {
  // dragon material → full, but if also enchantment >=8, 50% wins
  const highEnchant = (item.enchantment ?? 0) >= 8;
  if (highEnchant) return 0.5;
  return 1.0;
}

function findAndConsumeItem(pool: Item[], itemType: string): Item | undefined {
  // Choose the item that yields the worst (highest) reimbursement for the customer?
  // Spec is ambiguous. Use the first matching item to keep behavior deterministic.
  const idx = pool.findIndex(it => it.type === itemType);
  if (idx === -1) return undefined;
  return pool.splice(idx, 1)[0];
}

export function computeClaim(policy: PolicyRecord, incident: Incident): { payout: number; remainingCap: number } {
  // Validate damages: every damaged item type must be present in policy in sufficient count
  const pool: Item[] = policy.items.map(it => ({ ...it }));
  const resolved: { item: Item; amount: number }[] = [];

  for (const dmg of incident.damages) {
    if (dmg.amount < 0) {
      throw new Error(`Negative damage amount: ${dmg.amount}`);
    }
    if (!isKnownItemType(dmg.itemType)) {
      throw new Error(`Unknown item type in claim: ${dmg.itemType}`);
    }
    const item = findAndConsumeItem(pool, dmg.itemType);
    if (!item) {
      throw new Error(`Damaged item ${dmg.itemType} is not part of the policy`);
    }
    resolved.push({ item, amount: dmg.amount });
  }

  let totalPayout = 0;
  let remaining = policy.remainingCap;
  for (const { item, amount } of resolved) {
    const isDragon = item.material === 'dragon';
    const highEnchant = (item.enchantment ?? 0) >= 8;
    let reimbursable: number;
    if (highEnchant) {
      reimbursable = amount * 0.5;
    } else if (isDragon) {
      reimbursable = amount;
    } else {
      reimbursable = amount;
    }
    let perItem = reimbursable - DEDUCTIBLE;
    if (perItem < 0) perItem = 0;
    // Apply cap progressively
    const rounded = roundDown(perItem);
    const granted = Math.min(rounded, remaining);
    totalPayout += granted;
    remaining -= granted;
  }

  return { payout: totalPayout, remainingCap: remaining };
}

